import { isBackend } from './context';
export class Validators {
    static required = Object.assign((entity, col, message = undefined) => {
        if (!col.value ||
            (typeof col.value === 'string' && col.value.trim().length == 0))
            col.error = message || Validators.required.defaultMessage;
    }, {
        withMessage: (message) => {
            return (entity, col) => Validators.required(entity, col, message);
        },
        defaultMessage: 'Should not be empty',
    });
    static unique = Object.assign(async (entity, col, message = undefined) => {
        if (!col.entityRef)
            throw 'unique validation may only work on columns that are attached to an entity';
        if (col.entityRef.isNew() || col.valueChanged()) {
            if (await col.entityRef.repository.count({
                [col.metadata.key]: col.value,
            }))
                col.error = message || Validators.unique.defaultMessage;
        }
    }, {
        withMessage: (message) => {
            return (entity, col) => Validators.unique(entity, col, message);
        },
        defaultMessage: 'already exists',
    });
    static uniqueOnBackend = Object.assign(async (entity, col, message = undefined) => {
        if (isBackend())
            return Validators.unique(entity, col, message);
    }, {
        withMessage: (message) => {
            return (entity, col) => Validators.uniqueOnBackend(entity, col, message);
        },
    });
}
